package com.company.snackledger.kiosk;import com.company.snackledger.kiosk.api.Dto.ItemDto;import com.company.snackledger.kiosk.ui.Cart;import org.junit.jupiter.api.Test;import java.math.BigDecimal;import static org.junit.jupiter.api.Assertions.*;class CartTest{@Test void quantitiesAndRequestIdReuseUntilReset(){var cart=new Cart();var req=cart.requestId();cart.add(new ItemDto(1L,"Cola","100",new BigDecimal("1.25"),true));cart.add(new ItemDto(1L,"Cola","100",new BigDecimal("1.25"),true));assertEquals(new BigDecimal("2.50"),cart.total());assertEquals(req,cart.requestId());cart.clearForNewPurchase();assertNotEquals(req,cart.requestId());}}
